import { Injectable, OnModuleInit, Logger } from '@nestjs/common';
import { PrismaClient } from '@prisma/client';
import { Pool } from 'pg';
import { PrismaPg } from '@prisma/adapter-pg';
import 'dotenv/config';

@Injectable()
export class PrismaService extends PrismaClient implements OnModuleInit {
  private readonly logger = new Logger(PrismaService.name);

  constructor() {
    const dbUrl = process.env.DATABASE_URL;
    if (!dbUrl || typeof dbUrl !== 'string') {
      throw new Error(
        'DATABASE_URL is not set or not a string. Check your .env file.',
      );
    }

    // Ensure Pool gets a string connection string
    const pool = new Pool({
      connectionString: String(dbUrl),
    });

    const adapter = new PrismaPg(pool);

    // Enable Prisma query logging so SQL is printed to the console
    // Prisma constructor types are strict when using a custom adapter; this
    // line intentionally passes a runtime-built options object.
    // eslint-disable-next-line @typescript-eslint/no-unsafe-argument
    super({ adapter, log: ['query', 'info', 'warn', 'error'] } as any);

    // Log queries using Nest's logger for consistent output in VS Code terminal
    (this as any).$on('query', (e: any) => {
      this.logger.debug(
        `Prisma query: ${e.query} -- params: ${e.params} -- duration: ${e.duration}ms`,
      );
    });

    (this as any).$on('info', (e: any) =>
      this.logger.log(`Prisma info: ${JSON.stringify(e)}`),
    );
    (this as any).$on('warn', (e: any) =>
      this.logger.warn(`Prisma warn: ${JSON.stringify(e)}`),
    );
    (this as any).$on('error', (e: any) =>
      this.logger.error(`Prisma error: ${JSON.stringify(e)}`),
    );

    this.logger.log('PrismaService initialized');
  }

  async onModuleInit() {
    await this.$connect();
  }
}

import {
  Body,
  Controller,
  Get,
  Param,
  ParseUUIDPipe,
  Patch,
  Post,
  Query,
  UploadedFile,
  UseGuards,
  UseInterceptors,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { StudentRequestService } from './student-request.service';
import { CreateStudentRequestDto } from './dto/create-student-request.dto';
import { AuthGuard } from '../auth/guards/auth.guard';
import { RolesGuard } from '../auth/guards/roles.guard';
import { Roles } from '../auth/decorators/roles.decorator';

@UseGuards(AuthGuard, RolesGuard)
@Roles('STUDENT', 'ADMIN')
@Controller('student-request')
export class StudentRequestController {
  constructor(private readonly studentService: StudentRequestService) {}

  @Post('submit')
  @UseInterceptors(FileInterceptor('studentImage'))
  async submit(
    @UploadedFile() file: { filename?: string; originalname?: string },
    @Body() dto: CreateStudentRequestDto,
  ) {
    if (file) {
      dto.studentImage = file.filename || file.originalname;
    }
    return this.studentService.createRequest(dto);
  }

  @Get()
  async findAllRequests(
    @Query('status') status?: string,
    @Query('createdDate') createdDate?: string,
    @Query('page') page?: string,
    @Query('limit') limit?: string,
  ) {
    return this.studentService.findAllRequests({
      status,
      createdDate,
      page,
      limit,
    });
  }

  @Patch(':id/accept')
  @Roles('ADMIN')
  async acceptRequest(@Param('id', new ParseUUIDPipe()) id: string) {
    return this.studentService.acceptRequest(id);
  }

  @Patch(':id/reject')
  @Roles('ADMIN')
  async rejectRequest(@Param('id', new ParseUUIDPipe()) id: string) {
    return this.studentService.rejectRequest(id);
  }
}

import {
  Injectable,
  BadRequestException,
  NotFoundException,
  ConflictException,
} from '@nestjs/common';
import { StudentRequestStatus, Prisma } from '@prisma/client';
import { PrismaService } from '../prisma/prisma.service';
import { CreateStudentRequestDto } from './dto/create-student-request.dto';

@Injectable()
export class StudentRequestService {
  constructor(private readonly prisma: PrismaService) {}

  async createRequest(data: CreateStudentRequestDto) {
    if (!data) {
      throw new BadRequestException('Missing request body');
    }
    const siblingsArr = Array.isArray(data.siblings) ? data.siblings : [];
    const siblingsData = siblingsArr.map((s) => ({
      name: s?.name,
      grade: s?.grade,
    }));

    // convert registrationDate / dob if provided
    const parseDate = (v: any) => {
      if (!v) return undefined;
      const d = new Date(v);
      return isNaN(d.getTime()) ? undefined : d;
    };

    const registrationDate = parseDate(data.registrationDate);
    const dob = parseDate(data.dob);

    const toBoolean = (v: any) => {
      if (v === undefined || v === null) return undefined;
      if (typeof v === 'boolean') return v;
      const s = String(v).trim().toLowerCase();
      if (s === 'yes' || s === 'true') return true;
      if (s === 'no' || s === 'false') return false;
      return undefined;
    };
    const normalizeStudentMonitor = (v: any) => {
      if (typeof v === 'string') {
        const s = v.trim().toUpperCase();
        if (s === 'GIVEN' || s === 'NOT_GIVEN') return s;
      }
      return 'NOT_GIVEN';
    };

    const commonData = {
      fullNameWithSurname: data.fullNameWithSurname,
      nameWithInitials: data.nameWithInitials,
      dob,
      address: data.address,
      phone1: data.phone1,
      phone2: data.phone2,
      school: data.school,

      earlierSchool: toBoolean(data.earlierSchool),
      earlierSchoolReason: data.earlierSchoolReason,
      reasonForLeave: data.reasonForLeave,

      fatherFullName: data.fatherFullName,
      fatherJob: data.fatherJob,
      fatherJobAddress: data.fatherJobAddress,

      motherFullName: data.motherFullName,
      motherJob: data.motherJob,
      motherJobAddress: data.motherJobAddress,

      guardianFullName: data.guardianFullName,
      guardianJob: data.guardianJob,
      guardianJobAddress: data.guardianJobAddress,

      medicine: data.medicine,

      emergencyPersonName: data.emergencyPersonName,
      emergencyPersonAddress: data.emergencyPersonAddress,
      emergencyNumber: data.emergencyNumber,

      disabilities: data.disabilities,
      disabilityReason: data.disabilityReason,
      medicated: data.medicated,

      registrationPayment: data.registrationPayment,
      registrationDate,

      indexNo: data.indexNo,
      libraryNo: data.libraryNo,
      house: data.house,
      grade: data.grade,
      studentActiveMonitor: normalizeStudentMonitor(data.studentActiveMonitor),

      agreeToTerms: !!data.agreeToTerms,
      studentImage: data.studentImage,
    } as const;

    // Log the final payload so we can inspect enum values before Prisma call
    // (remove or lower log level in production)

    console.debug('studentRequest.create payload:', JSON.stringify(commonData));

    const created = await this.prisma.studentRequest.create({
      data: {
        ...commonData,
        siblings: siblingsData.length ? { create: siblingsData } : undefined,
      },
      include: { siblings: true },
    });

    return this.mapRequest(created);
  }

  async findAllRequests(params?: {
    status?: string;
    createdDate?: string;
    page?: string | number;
    limit?: string | number;
  }) {
    const page = params?.page ? Number(params.page) : 1;
    const limit = params?.limit ? Number(params.limit) : 15;

    const filters: Prisma.StudentRequestWhereInput[] = [];

    if (params?.status && params.status.trim() !== '') {
      const upperStatus = params.status
        .trim()
        .toUpperCase() as StudentRequestStatus;
      if (Object.values(StudentRequestStatus).includes(upperStatus)) {
        filters.push({ status: upperStatus });
      }
    }

    if (params?.createdDate && params.createdDate.trim() !== '') {
      const date = new Date(params.createdDate.trim());
      if (!isNaN(date.getTime())) {
        const startOfDay = new Date(date);
        startOfDay.setUTCHours(0, 0, 0, 0);

        const endOfDay = new Date(date);
        endOfDay.setUTCHours(23, 59, 59, 999);

        filters.push({
          createdAt: {
            gte: startOfDay,
            lte: endOfDay,
          },
        });
      }
    }

    const where = filters.length > 0 ? { AND: filters } : {};

    const total = await this.prisma.studentRequest.count({ where });

    const results = await this.prisma.studentRequest.findMany({
      where,
      skip: (page - 1) * limit,
      take: limit,
      include: { siblings: true },
      orderBy: { createdAt: 'desc' },
    });

    const data = results.map((r) => this.mapRequest(r));

    return {
      data,
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit),
    };
  }

  async acceptRequest(requestId: string) {
    const request = await this.prisma.studentRequest.findUnique({
      where: { id: requestId },
      include: { siblings: true },
    });

    if (!request) {
      throw new NotFoundException('Student request not found');
    }

    if (request.status !== StudentRequestStatus.PENDING) {
      throw new ConflictException(
        `Student request is already ${request.status.toLowerCase()}`,
      );
    }

    const student = await this.prisma.$transaction(async (tx) => {
      const createdStudent = await tx.student.create({
        data: {
          fullNameWithSurname: request.fullNameWithSurname,
          nameWithInitials: request.nameWithInitials,
          dob: request.dob,
          address: request.address,
          phone1: request.phone1,
          phone2: request.phone2,
          school: request.school,

          earlierSchool: request.earlierSchool,
          earlierSchoolReason: request.earlierSchoolReason,
          reasonForLeave: request.reasonForLeave,

          fatherFullName: request.fatherFullName,
          fatherJob: request.fatherJob,
          fatherJobAddress: request.fatherJobAddress,

          motherFullName: request.motherFullName,
          motherJob: request.motherJob,
          motherJobAddress: request.motherJobAddress,

          guardianFullName: request.guardianFullName,
          guardianJob: request.guardianJob,
          guardianJobAddress: request.guardianJobAddress,

          medicine: request.medicine,

          emergencyPersonName: request.emergencyPersonName,
          emergencyPersonAddress: request.emergencyPersonAddress,
          emergencyNumber: request.emergencyNumber,

          disabilities: request.disabilities,
          disabilityReason: request.disabilityReason,
          medicated: request.medicated,

          registrationPayment: request.registrationPayment,
          registrationDate: request.registrationDate,

          indexNo: request.indexNo,
          libraryNo: request.libraryNo,
          house: request.house,
          grade: request.grade,
          studentActiveMonitor: request.studentActiveMonitor,

          agreeToTerms: request.agreeToTerms,
          studentImage: request.studentImage,

          siblings: request.siblings.length
            ? {
                create: request.siblings.map((sibling) => ({
                  name: sibling.name,
                  grade: sibling.grade,
                })),
              }
            : undefined,
        },
        include: { siblings: true },
      });

      await tx.studentRequest.update({
        where: { id: requestId },
        data: { status: StudentRequestStatus.ACCEPTED },
      });

      return createdStudent;
    });

    return {
      message: 'Student request accepted and student created successfully',
      student,
    };
  }

  async rejectRequest(requestId: string) {
    const request = await this.prisma.studentRequest.findUnique({
      where: { id: requestId },
    });

    if (!request) {
      throw new NotFoundException('Student request not found');
    }

    if (request.status !== StudentRequestStatus.PENDING) {
      throw new ConflictException(
        `Student request is already ${request.status.toLowerCase()}`,
      );
    }

    const updated = await this.prisma.studentRequest.update({
      where: { id: requestId },
      data: { status: StudentRequestStatus.REJECTED },
    });

    return {
      message: 'Student request rejected successfully',
      request: this.mapRequest(updated),
    };
  }

  private mapRequest(r: any) {
    // ensure grade is present and convert dob to a birthday string (YYYY-MM-DD)
    const birthday = r?.dob
      ? new Date(r.dob).toISOString().split('T')[0]
      : null;

    return {
      ...r,
      birthday,
      // keep `dob` for compatibility, and `grade` is already present
    } as const;
  }
}

import {
  Injectable,
  BadRequestException,
  NotFoundException,
} from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { CreateStudentDto } from './dto/create-student.dto';
import { UpdateStudentDto } from './dto/update-student.dto';

@Injectable()
export class StudentService {
  constructor(private readonly prisma: PrismaService) {}

  async create(data: CreateStudentDto) {
    if (!data) {
      throw new BadRequestException('Missing request body');
    }

    const siblingsArr = Array.isArray(data.siblings) ? data.siblings : [];
    const siblingsData = siblingsArr.map((s) => ({
      name: s?.name,
      grade: s?.grade,
    }));

    const registrationDate = data.registrationDate
      ? new Date(data.registrationDate)
      : undefined;
    const dob = data.dob ? new Date(data.dob) : undefined;

    return this.prisma.student.create({
      data: {
        fullNameWithSurname: data.fullNameWithSurname,
        nameWithInitials: data.nameWithInitials,
        dob,
        address: data.address,
        phone1: data.phone1,
        phone2: data.phone2,
        school: data.school,

        earlierSchool: !!data.earlierSchool,
        earlierSchoolReason: data.earlierSchoolReason,
        reasonForLeave: data.reasonForLeave,

        fatherFullName: data.fatherFullName,
        fatherJob: data.fatherJob,
        fatherJobAddress: data.fatherJobAddress,

        motherFullName: data.motherFullName,
        motherJob: data.motherJob,
        motherJobAddress: data.motherJobAddress,

        guardianFullName: data.guardianFullName,
        guardianJob: data.guardianJob,
        guardianJobAddress: data.guardianJobAddress,

        medicine: data.medicine,

        emergencyPersonName: data.emergencyPersonName,
        emergencyPersonAddress: data.emergencyPersonAddress,
        emergencyNumber: data.emergencyNumber,

        disabilities: !!data.disabilities,
        disabilityReason: data.disabilityReason,
        medicated: !!data.medicated,

        registrationPayment: data.registrationPayment,
        registrationDate,

        indexNo: data.indexNo,
        libraryNo: data.libraryNo,
        house: data.house,
        grade: data.grade,
        studentActiveMonitor: data.studentActiveMonitor || 'NOT_GIVEN',

        agreeToTerms: !!data.agreeToTerms,
        studentImage: data.studentImage,

        siblings: siblingsData.length ? { create: siblingsData } : undefined,
      },
      include: { siblings: true },
    });
  }

  async findAll(
    grade?: string,
    name?: string,
    pageParam?: string | number,
    limitParam?: string | number,
  ) {
    const filters: any[] = [];

    if (grade && grade.trim() !== '') {
      filters.push({ grade: grade.trim() });
    }

    if (name && name.trim() !== '') {
      filters.push({
        OR: [
          {
            fullNameWithSurname: { contains: name.trim(), mode: 'insensitive' },
          },
          { nameWithInitials: { contains: name.trim(), mode: 'insensitive' } },
          { address: { contains: name.trim(), mode: 'insensitive' } },
        ],
      });
    }

    const where = filters.length > 0 ? { AND: filters } : {};

    const page = pageParam ? Number(pageParam) : 1;
    const limit = limitParam ? Number(limitParam) : 15;

    const total = await this.prisma.student.count({ where });

    const data = await this.prisma.student.findMany({
      where,
      skip: (page - 1) * limit,
      take: limit,
      include: { siblings: true },
      orderBy: { createdAt: 'desc' },
    });

    return {
      data,
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit),
    };
  }

  async findOne(id: string) {
    const student = await this.prisma.student.findUnique({
      where: { id },
      include: { siblings: true },
    });

    if (!student) {
      throw new NotFoundException('Student not found');
    }

    return student;
  }

  async update(id: string, data: UpdateStudentDto) {
    const existing = await this.prisma.student.findUnique({
      where: { id },
      select: { id: true },
    });

    if (!existing) {
      throw new NotFoundException('Student not found');
    }

    const siblingsArr = Array.isArray(data.siblings)
      ? data.siblings
      : undefined;
    const siblingsData = siblingsArr?.map((s) => ({
      name: s?.name,
      grade: s?.grade,
    }));

    const updateData: any = {
      fullNameWithSurname: data.fullNameWithSurname,
      nameWithInitials: data.nameWithInitials,
      address: data.address,
      phone1: data.phone1,
      phone2: data.phone2,
      school: data.school,
      earlierSchoolReason: data.earlierSchoolReason,
      reasonForLeave: data.reasonForLeave,
      fatherFullName: data.fatherFullName,
      fatherJob: data.fatherJob,
      fatherJobAddress: data.fatherJobAddress,
      motherFullName: data.motherFullName,
      motherJob: data.motherJob,
      motherJobAddress: data.motherJobAddress,
      guardianFullName: data.guardianFullName,
      guardianJob: data.guardianJob,
      guardianJobAddress: data.guardianJobAddress,
      emergencyPersonName: data.emergencyPersonName,
      emergencyPersonAddress: data.emergencyPersonAddress,
      emergencyNumber: data.emergencyNumber,
      disabilityReason: data.disabilityReason,
      medicine: data.medicine,
      registrationPayment: data.registrationPayment,
      indexNo: data.indexNo,
      libraryNo: data.libraryNo,
      house: data.house,
      grade: data.grade,
      studentActiveMonitor: data.studentActiveMonitor,
      studentImage: data.studentImage,
    };

    if (data.dob !== undefined) {
      updateData.dob = data.dob ? new Date(data.dob) : null;
    }

    if (data.registrationDate !== undefined) {
      updateData.registrationDate = data.registrationDate
        ? new Date(data.registrationDate)
        : null;
    }

    if (data.earlierSchool !== undefined) {
      updateData.earlierSchool = !!data.earlierSchool;
    }

    if (data.disabilities !== undefined) {
      updateData.disabilities = data.disabilities;
    }

    if (data.medicated !== undefined) {
      updateData.medicated = data.medicated;
    }

    if (data.agreeToTerms !== undefined) {
      updateData.agreeToTerms = !!data.agreeToTerms;
    }

    if (siblingsData !== undefined) {
      updateData.siblings = {
        deleteMany: {},
        create: siblingsData,
      };
    }

    return this.prisma.student.update({
      where: { id },
      data: updateData,
      include: { siblings: true },
    });
  }
}
